hints.text:
Serial.Open();
var data = Serial.ReadLine();
var parts = data.Split(',');
var temp = parts[1].Split('=')[1];
var hum = parts[2].Split('=')[1];
Print($"温度: {temp}°C, 湿度: {hum}%");
Serial.Close();
